}/**
 * Gmail batch operations utility for efficient bulk filter management.
 * Uses Gmail's batch API to process up to 100 filters per API call.
 * Provides error handling and per-item response tracking.
 */

import { FilterDefinitionsSchema, FilterResponseSchema, BatchSummarySchema } from '../src/schemas/gmail-batch-types.ts';

const BATCH_SIZE = 100;

/**
 * Create multiple filters using Gmail's batch API.
 * Groups filters into batches of up to 100 and processes each batch.
 * Returns response for each filter with success status and ID/error.
 *
 * @param {Object} gmail - Authenticated Gmail client
 * @param {string} userId - User ID (typically 'me')
 * @param {Array} filters - Array of filter definitions to create
 * @returns {Promise<Array>} Array of responses, one per input filter
 */
export async function batchCreateFilters(gmail, userId, filters) {
  // Validate input
  const validatedFilters = FilterDefinitionsSchema.parse(filters);
  const responses = [];

  // Process filters in batches
  for (let i = 0; i < validatedFilters.length; i += BATCH_SIZE) {
    const batchFilters = validatedFilters.slice(i, i + BATCH_SIZE);
    const batchResponses = await processBatch(gmail, userId, batchFilters);
    responses.push(...batchResponses);
  }

  return responses;
}

/**
 * Process a single batch of filters.
 * Creates individual filter requests and executes them in parallel.
 *
 * @private
 * @param {Object} gmail - Authenticated Gmail client
 * @param {string} userId - User ID
 * @param {FilterDefinition[]} batch - Batch of filter definitions
 * @returns {Promise<FilterResponse[]>} Responses for this batch
 */
async function processBatch(gmail, userId, batch) {
  const promises = batch.map(filter =>
    createSingleFilter(gmail, userId, filter)
  );

  return Promise.all(promises);
}

/**
 * Create a single filter with error handling.
 *
 * @private
 * @param {Object} gmail - Authenticated Gmail client
 * @param {string} userId - User ID
 * @param {Object} filter - Filter definition
 * @returns {Promise<Object>} Response with success status
 */
async function createSingleFilter(gmail, userId, filter) {
  try {
    const response = await gmail.users.settings.filters.create({
      userId,
      requestBody: filter
    });

    return FilterResponseSchema.parse({
      success: true,
      filterId: response.data.id || null,
      error: null
    });
  } catch (error) {
    return FilterResponseSchema.parse({
      success: false,
      filterId: null,
      error: error.message || 'Unknown error'
    });
  }
}

/**
 * Create multiple filters with individual result tracking and summary.
 * This is a convenience wrapper that calls batchCreateFilters and provides
 * a summary of successes and failures.
 *
 * @param {Object} gmail - Authenticated Gmail client
 * @param {string} userId - User ID
 * @param {Array} filters - Filters to create
 * @returns {Promise<Object>} Summary object with successful/failed counts and results
 */
export async function batchCreateFiltersWithSummary(gmail, userId, filters) {
  const results = await batchCreateFilters(gmail, userId, filters);

  const successful = results.filter(r => r.success).length;
  const failed = results.filter(r => !r.success).length;

  return BatchSummarySchema.parse({
    successful,
    failed,
    results
  });
}import fs from 'fs';
import path from 'path';
import { homedir } from 'os';
import { google } from 'googleapis';
import { OAuth2Client } from 'google-auth-library';

/**
 * Creates an authenticated Gmail client.
 * Reads tokens and credentials from environment-configured paths.
 *
 * Environment variables:
 * - ACCOUNT_MODE: Account key to use (default: 'normal')
 * - GOOGLE_OAUTH_CREDENTIALS: Path to credentials.json (default: './credentials.json')
 *
 * Token file location: ~/.config/google-calendar-mcp/tokens-gmail.json
 *
 * @returns {Object} Gmail API client authenticated and ready for requests
 * @throws {Error} If token file is missing, credentials are invalid, or token for account mode not found
 */
export function createGmailClient() {
  const TOKEN_PATH = path.join(homedir(), '.config/google-calendar-mcp/tokens-gmail.json');
  const credPath = process.env.GOOGLE_OAUTH_CREDENTIALS || './credentials.json';

  // Read both files synchronously to ensure consistency.
  // While TOCTOU (Time-of-check, time-of-use) risk is very low in local dev,
  // this approach minimizes the window between reads and ensures token/credentials
  // are coherent at the time of OAuth2Client creation.
  const tokenFileData = JSON.parse(fs.readFileSync(TOKEN_PATH, 'utf-8'));
  const credData = JSON.parse(fs.readFileSync(credPath, 'utf-8'));

  const accountMode = process.env.ACCOUNT_MODE || 'normal';
  const tokenData = tokenFileData[accountMode];

  if (!tokenData) {
    throw new Error(`No token found for account mode: ${accountMode}`);
  }

  const oauth2Client = new OAuth2Client(
    credData.installed.client_id,
    credData.installed.client_secret,
    credData.installed.redirect_uris[0]
  );
  oauth2Client.setCredentials(tokenData);

  return google.gmail({ version: 'v1', auth: oauth2Client });
}import { USER_ID } from './constants.mjs';
import { buildLabelCache } from './gmail-label-utils.mjs';

/**
 * Resolves an existing label ID by name, or creates the label if absent.
 *
 * @param {Object} gmail - Gmail API client
 * @param {string} labelName - Label name (supports hierarchical e.g. "Parent/Child")
 * @returns {Promise<string>} Label ID
 */
export async function ensureLabelExists(gmail, labelName) {
  const labelCache = await buildLabelCache(gmail);
  const existing = labelCache.get(labelName);
  if (existing) return existing;

  const res = await gmail.users.labels.create({
    userId: USER_ID,
    requestBody: {
      name: labelName,
      labelListVisibility: 'labelShow',
      messageListVisibility: 'show',
    },
  });
  return res.data.id;
}

/**
 * Creates a Gmail filter. Returns the filter ID, or null if it already exists.
 * Throws for any other error.
 *
 * @param {Object} gmail - Gmail API client
 * @param {Object} criteria - Filter criteria (from, to, subject, query, etc.)
 * @param {Object} action - Filter action (addLabelIds, removeLabelIds, etc.)
 * @returns {Promise<string|null>} Filter ID or null if already exists
 */
export async function createGmailFilter(gmail, criteria, action) {
  try {
    const res = await gmail.users.settings.filters.create({
      userId: USER_ID,
      requestBody: { criteria, action },
    });
    return res.data.id;
  } catch (error) {
    // Google returns HTTP 400 with message containing 'Filter already exists' for duplicate filters
    if (error.code === 409 || error.message?.includes('Filter already exists')) return null;
    throw error;
  }
