const ONE_HOUR_MS = 60 * 60 * 1000;
const HALF_HOUR_MS = 30 * 60 * 1000;
export interface EventCreateResult {
  eventId: string;
  result: unknown;
}
export interface EventUpdateResult {
  result: unknown;
  text: string;
