    );
    const sharedSchemaUsage = [
      /timeMin:\s*[A-Z][a-zA-Z]*Schema/,
      /timeMax:\s*[A-Z][a-zA-Z]*Schema/,
      /start:\s*[A-Z][a-zA-Z]*Schema/,
      /end:\s*[A-Z][a-zA-Z]*Schema/,
      /calendarId:\s*[A-Z][a-zA-Z]*Schema/,
      /eventId:\s*[A-Z][a-zA-Z]*Schema/,
      /query:\s*[A-Z][a-zA-Z]*Schema/,
      /summary:\s*[A-Z][a-zA-Z]*Schema/,
      /description:\s*[A-Z][a-zA-Z]*Schema/,
      /location:\s*[A-Z][a-zA-Z]*Schema/,
      /colorId:\s*[A-Z][a-zA-Z]*Schema/,
      /reminders:\s*[A-Z][a-zA-Z]*Schema/,
      /attendees:\s*[A-Z][a-zA-Z]*Schema/,
      /email:\s*[A-Z][a-zA-Z]*Schema/
    ];
    for (const pattern of sharedSchemaUsage) {
      const matches = registryCode.match(pattern);
