.cache//**
 * Mark emails as read based on label membership or past-event date detection.
 *
 * Usage:
 *   node mark-read.mjs                  # mark all labeled emails as read
 *   node mark-read.mjs --archived-only  # restrict to emails no longer in inbox
 *   node mark-read.mjs --past-events    # mark only past-date event emails as read
 */
import { createGmailClient } from './lib/gmail-client.mjs';
import {
  USER_ID,
  GMAIL_UNREAD,
  LABEL_EVENTS, LABEL_PRODUCT_UPDATES, LABEL_COMMUNITIES,
  LABEL_SERVICES, LABEL_BILLING, LABEL_MONITORING,
} from './lib/constants.mjs';
import { extractEventDate, isPastEvent } from './lib/date-based-filter.mjs';
import { getHeader } from './lib/email-utils.mjs';
import { batchModifyMessages, searchAndModify } from './lib/gmail-batch-utils.mjs';
import { decodeMessageBody } from './lib/gmail-message-utils.mjs';

const pastEventsMode = process.argv.includes('--past-events');
const archivedOnly = process.argv.includes('--archived-only');

const LABELED_LABELS = [LABEL_EVENTS, LABEL_PRODUCT_UPDATES, LABEL_COMMUNITIES, LABEL_SERVICES, LABEL_BILLING, LABEL_MONITORING];

async function markLabeledRead(gmail) {
  const archiveSuffix = archivedOnly ? ' -label:INBOX' : '';
  let total = 0;
  for (const label of LABELED_LABELS) {
    const count = await searchAndModify(gmail, `label:"${label}" is:unread${archiveSuffix}`, { removeLabelIds: [GMAIL_UNREAD] });
    if (count > 0) console.log(`${label}: ${count} marked as read`);
    total += count;
  }
  const qualifier = archivedOnly ? 'archived ' : '';
  console.log(`Total: ${total} ${qualifier}emails marked as read`);
}

async function markPastEventsRead(gmail) {
  const searchResponse = await gmail.users.messages.list({
    userId: USER_ID,
    q: `label:${LABEL_EVENTS} is:unread`,
    maxResults: 500,
  });

  const messageIds = searchResponse.data.messages || [];
  console.log(`Found ${messageIds.length} unread event emails`);
  if (messageIds.length === 0) return;

  const fullMsgs = await Promise.all(
    messageIds.map(msg =>
      gmail.users.messages.get({ userId: USER_ID, id: msg.id, format: 'full' })
    )
  );

  const pastIds = fullMsgs
    .filter(fullMsg => {
      const headers = fullMsg.data.payload?.headers || [];
      const subject = getHeader(headers, 'Subject');
      const body = decodeMessageBody(fullMsg.data.payload);
      const eventDate = extractEventDate(subject + '\n' + body);
      return eventDate && isPastEvent(eventDate);
    })
    .map(fullMsg => fullMsg.data.id);

  console.log(`Identified ${pastIds.length} past events`);
  if (pastIds.length === 0) return;

  await batchModifyMessages(gmail, pastIds, { removeLabelIds: [GMAIL_UNREAD] });
  console.log(`Past events marked as read: ${pastIds.length}`);
  console.log(`Future events remaining unread: ${messageIds.length - pastIds.length}`);
}

const gmail = createGmailClient();
const action = pastEventsMode ? markPastEventsRead : markLabeledRead;
action(gmail).catch(error => {
  console.error('Error:', error.message);
  process.exit(1);
});/**
 * Date-based email filter utility
 * Abstracts logic for organizing emails by event date (past vs future)
 */
import { GMAIL_INBOX } from './constants.mjs';

/**
 * Parse event date from email content
 * Supports multiple date formats
 * @param {string} content - Email subject or body text
 * @returns {Date|null} Parsed date or null if not found
 */
export function extractEventDate(content) {
  if (!content) return null;

  const today = new Date();
  const currentYear = today.getFullYear();

  const months = {
    jan: 0, january: 0,
    feb: 1, february: 1,
    mar: 2, march: 2,
    apr: 3, april: 3,
    may: 4,
    jun: 5, june: 5,
    jul: 6, july: 6,
    aug: 7, august: 7,
    sep: 8, september: 8,
    oct: 9, october: 9,
    nov: 10, november: 10,
    dec: 11, december: 11
  };

  // Try ISO format: 2026-03-25 or 2026/03/25
  let match = content.match(/(\d{4})[-\/](\d{1,2})[-\/](\d{1,2})/);
  if (match) {
    const year = parseInt(match[1]);
    const month = parseInt(match[2]) - 1;
    const day = parseInt(match[3]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      return new Date(year, month, day);
    }
  }

  // Try MM/DD/YYYY or MM-DD-YYYY
  match = content.match(/(\d{1,2})[-\/](\d{1,2})[-\/](\d{4})/);
  if (match) {
    const month = parseInt(match[1]) - 1;
    const day = parseInt(match[2]);
    const year = parseInt(match[3]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      return new Date(year, month, day);
    }
  }

  // Try M/D or MM/DD (assume current or next year)
  match = content.match(/(?:^|\s)(\d{1,2})\/(\d{1,2})(?:\s|$)/);
  if (match) {
    const month = parseInt(match[1]) - 1;
    const day = parseInt(match[2]);
    if (month >= 0 && month <= 11 && day >= 1 && day <= 31) {
      let year = currentYear;
      // If month/day has passed, assume next year
      const testDate = new Date(year, month, day);
      if (testDate < today) {
        year = currentYear + 1;
      }
      return new Date(year, month, day);
    }
  }

  // Try "Month Day, Year" or "Month Day" formats
  match = content.match(/([A-Za-z]+)\s+(\d{1,2}),?\s+(\d{4})?/);
  if (match) {
    const monthStr = match[1];
    const day = parseInt(match[2]);
    const year = match[3] ? parseInt(match[3]) : currentYear;
    const monthIndex = months[monthStr.toLowerCase().substring(0, 3)];

    if (monthIndex !== undefined && day >= 1 && day <= 31) {
      return new Date(year, monthIndex, day);
    }
  }

  // Try "Day Mon DD" format: "@ Mon, Mar 23" or "@ Fri 25"
  match = content.match(/(?:@\s+)?(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun),?\s+([A-Za-z]+)?\s+(\d{1,2})/i);
  if (match) {
    const monthStr = match[1];
    const day = parseInt(match[2]);

    if (monthStr) {
      const monthIndex = months[monthStr.toLowerCase().substring(0, 3)];
      if (monthIndex !== undefined && day >= 1 && day <= 31) {
        let year = currentYear;
        const testDate = new Date(year, monthIndex, day);
        if (testDate < today) {
          year = currentYear + 1;
        }
        return new Date(year, monthIndex, day);
      }
    }
  }

  return null;
}

/**
 * Determine if event is in the past
 * @param {Date|null} eventDate - Event date (null if unknown)
 * @returns {boolean|null} true if past, false if future, null if unknown
 */
export function isPastEvent(eventDate) {
  if (!eventDate) return null;

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const normalized = new Date(eventDate);
  normalized.setHours(0, 0, 0, 0);

  return normalized < today;
}

/**
 * Classify email by event recency
 * @param {string} emailSubject - Email subject line
 * @param {string} emailBody - Email body content
 * @returns {object} Classification result
 *   - status: 'future' | 'past' | 'unknown'
 *   - eventDate: Date|null
 *   - reason: string (explanation)
 */
export function classifyEmail(emailSubject, emailBody) {
  // Try to extract date from subject first, then body
  const eventDate = extractEventDate(emailSubject) || extractEventDate(emailBody);

  if (!eventDate) {
    return {
      status: 'unknown',
      eventDate: null,
      reason: 'Could not parse event date'
    };
  }

  const isPast = isPastEvent(eventDate);
  const dateStr = eventDate.toLocaleDateString('en-US', {
    weekday: 'short',
    month: 'short',
    day: 'numeric'
  });

  if (isPast) {
    return {
      status: 'past',
      eventDate,
      reason: `Event was ${dateStr}`
    };
  }

  return {
    status: 'future',
    eventDate,
    reason: `Event is ${dateStr}`
  };
}

/**
 * Determine Gmail actions based on email classification
 * @param {string} status - Classification status ('future' | 'past' | 'unknown')
 * @param {string} futureLabel - Label ID to apply to future events
 * @param {boolean} archivePast - Whether to archive past events (default: true)
 * @returns {object} Gmail API action object
 *   - addLabelIds: [label IDs to add]
 *   - removeLabelIds: [label IDs to remove]
 */
export function getGmailAction(status, futureLabel, archivePast = true) {
  const action = {
    addLabelIds: futureLabel ? [futureLabel] : [],
    removeLabelIds: []
  };

  if (status === 'past' && archivePast) {
    action.removeLabelIds.push(GMAIL_INBOX);
  }

  return action;
}

/**
 * Process a batch of emails with date-based filtering
 * @param {object[]} emails - Array of email objects with id, subject, body
 * @param {string} futureLabel - Label ID for future events
 * @param {boolean} archivePast - Whether to archive past events
 * @returns {object} Results with categorized emails
 *   - future: [email ids]
 *   - past: [email ids]
 *   - unknown: [email ids]
 *   - classifications: [email classifications]
 */
export function classifyEmails(emails, futureLabel, archivePast = true) {
  const results = {
    future: [],
    past: [],
    unknown: [],
    classifications: []
  };

  for (const email of emails) {
    const classification = classifyEmail(email.subject, email.body);
    classification.id = email.id;
    classification.action = getGmailAction(classification.status, futureLabel, archivePast);

    results.classifications.push(classification);
    results[classification.status].push(email.id);
  }

  return results;
}/**
 * Gmail label creation and pattern application utilities.
 * Shared helpers for bulk label operations across create-*.mjs scripts.
 */

import { USER_ID } from './constants.mjs';
import { LabelPatternSchema, LabelIdMapSchema } from '../src/schemas/gmail-label-utils-types.ts';

/**
 * Create Gmail labels and track their IDs.
 * Handles conflicts when labels already exist by fetching existing ID.
 *
 * @param {Object} gmail - Gmail API client
 * @param {string[]} labelNames - Array of label names to create (can be hierarchical: "Parent/Child")
 * @param {Object} labelIds - Object to store mapping of label names to their IDs
 * @param {Map} existingLabelMap - Map of existing label names to IDs (for conflict resolution)
 * @returns {Promise<void>}
 */
export async function createLabels(gmail, labelNames, labelIds, existingLabelMap) {
  // Validate labelNames
  if (!Array.isArray(labelNames) || !labelNames.every(name => typeof name === 'string')) {
    throw new Error('labelNames must be an array of strings');
  }
  for (const labelName of labelNames) {
    try {
      const response = await gmail.users.labels.create({
        userId: USER_ID,
        requestBody: {
          name: labelName,
          labelListVisibility: 'labelShow',
          messageListVisibility: 'show',
        },
      });

      console.log(`✅ ${labelName}`);
      labelIds[labelName] = response.data.id;
    } catch (error) {
      if (error.message.includes('exists')) {
        const existingId = existingLabelMap.get(labelName);
        if (existingId) {
          console.log(`⚠️  Exists: ${labelName}`);
          labelIds[labelName] = existingId;
        }
      } else {
        console.error(`❌ Failed ${labelName}: ${error.message}`);
      }
    }
  }
}

/**
 * Apply label patterns to existing emails based on query criteria.
 * Searches for emails matching pattern queries and labels them accordingly.
 *
 * @param {Object} gmail - Gmail API client
 * @param {Array} patterns - Array of patterns with label names and queries
 * @param {Object} labelIds - Map of label names to their IDs (populated by createLabels)
 * @returns {Promise<number>} Total number of emails labeled
 */
export async function applyPatterns(gmail, patterns, labelIds) {
  // Validate input
  const validatedPatterns = LabelPatternSchema.array().parse(patterns);
  const validatedLabelIds = LabelIdMapSchema.parse(labelIds);

  let total = 0;

  for (const pattern of validatedPatterns) {
    try {
      const searchResult = await gmail.users.messages.list({
        userId: USER_ID,
        q: pattern.query,
        maxResults: 100,
      });

      if (!searchResult.data.messages) continue;

      const messageIds = searchResult.data.messages.map(m => m.id);
      const count = messageIds.length;

      if (count > 0) {
        const labelId = labelIds[pattern.label];
        if (!labelId) {
          console.error(`  ❌ No label ID resolved for ${pattern.label}, skipping`);
          continue;
        }

        await gmail.users.messages.batchModify({
          userId: USER_ID,
          requestBody: {
            ids: messageIds,
            addLabelIds: [labelId],
          },
        });

        console.log(`  ✅ ${pattern.label.split('/').pop()}: ${count}`);
        total += count;
      }
    } catch (error) {
      console.error(`  ❌ Failed ${pattern.label}: ${error.message}`);
    }
  }

  return total;
}

/**
 * Build a cache of all label names to their IDs.
 * Enables runtime label ID resolution instead of hardcoded values.
 *
 * @param {Object} gmail - Gmail API client
 * @returns {Promise<Map<string, string>>} Map of label names to their IDs
 */
export async function buildLabelCache(gmail) {
  const response = await gmail.users.labels.list({
    userId: USER_ID,
    fields: 'labels(id,name)',
  });

  const labelCache = new Map();
  for (const label of response.data.labels || []) {
    labelCache.set(label.name, label.id);
  }
  return labelCache;
}

/**
 * Resolve a single label ID by name using a cache for efficiency.
 *
 * @param {Object} gmail - Gmail API client
 * @param {string} labelName - Name of the label (e.g., "Events/Workshops")
 * @param {Map<string, string>} labelCache - Cache of label names to IDs
 * @returns {Promise<string|null>} Label ID or null if not found
 */
export async function resolveLabelId(gmail, labelName, labelCache) {
  if (labelCache.has(labelName)) {
    return labelCache.get(labelName);
  }

  // Cache miss - rebuild and retry (labels may have been created)
  const updatedCache = await buildLabelCache(gmail);
  return updatedCache.get(labelName) || null;
}

/**
 * Resolve multiple label IDs by name at once.
 *
 * @param {Object} gmail - Gmail API client
 * @param {string[]} labelNames - Array of label names to resolve
 * @returns {Promise<Map<string, string>>} Map of label names to their IDs
 */
export async function resolveLabelIds(gmail, labelNames) {
  const labelCache = await buildLabelCache(gmail);
  const result = new Map();

  for (const labelName of labelNames) {
    const id = labelCache.get(labelName);
    if (id) {
      result.set(labelName, id);
    }
  }

  return result;
}import { USER_ID } from './constants.mjs';
import { getHeader } from './email-utils.mjs';

/**
 * Decodes the plain-text body from a Gmail message payload.
 * Checks direct body data first, then looks for a text/plain part.
 *
 * @param {Object} payload - message.data.payload
 * @returns {string}
 */
export function decodeMessageBody(payload) {
  if (payload?.body?.data) {
    return Buffer.from(payload.body.data, 'base64').toString('utf-8');
  }
  const textPart = payload?.parts?.find(p => p.mimeType === 'text/plain');
  if (textPart?.body?.data) {
    return Buffer.from(textPart.body.data, 'base64').toString('utf-8');
  }
  console.warn('decodeMessageBody: no text/plain body found in payload');
  return '';
}

/**
 * Fetches messages under a label and returns their metadata (Subject, From, Date).
 * Handles individual fetch failures by filtering them out.
 *
 * @param {Object} gmail - Gmail API client
 * @param {string} labelId - Label ID to query
 * @param {Object} [options]
 * @param {number} [options.maxResults=100] - Max results from messages.list
 * @param {number} [options.limit] - Cap on how many messages to fetch metadata for
 * @returns {Promise<{total: number, messages: Array<{subject: string, from: string, date: string}>}>}
 */
export async function fetchLabeledMessageMetadata(gmail, labelId, { maxResults = 100, limit } = {}) {
  const result = await gmail.users.messages.list({
    userId: USER_ID,
    labelIds: [labelId],
    maxResults,
  });

  const messageHeaders = result.data.messages || [];
  const toFetch = limit ? messageHeaders.slice(0, limit) : messageHeaders;

  const fullMsgs = await Promise.all(
    toFetch.map(({ id }) =>
      gmail.users.messages.get({
        userId: USER_ID,
        id,
        format: 'metadata',
        metadataHeaders: ['Subject', 'From', 'Date'],
      }).catch(() => null)
    )
  );

  return {
    total: messageHeaders.length,
    messages: fullMsgs
      .filter(Boolean)
      .map(msg => {
        const headers = msg.data.payload?.headers || [];
        return {
          subject: getHeader(headers, 'Subject', '(no subject)'),
          from: getHeader(headers, 'From', '(unknown)'),
          date: getHeader(headers, 'Date', '(no date)'),
        };
      }),
  };
