  performConflictCheck,
  getConferenceAndAttachmentOptions,
} from "./eventManipulationUtils.js";
import { DuplicateInfo } from "../../services/conflict-detection/types.js";
export class CreateEventHandler extends BaseToolHandler {
    private conflictDetectionService: ConflictDetectionService;
    constructor() {
        super();
        this.conflictDetectionService = new ConflictDetectionService();
    }
    async runTool(args: any, oauth2Client: OAuth2Client): Promise<CallToolResult> {
        const validArgs = args as CreateEventInput;
        const timezone = args.timeZone || await this.getCalendarTimezone(oauth2Client, validArgs.calendarId);
        const eventToCheck = buildEventForConflictCheckCreate(validArgs, timezone);
        const conflicts = await performConflictCheck(
            this.conflictDetectionService,
            oauth2Client,
            eventToCheck,
            validArgs.calendarId,
            {
                checkDuplicates: true,
                checkConflicts: true,
                calendarsToCheck: validArgs.calendarsToCheck || [validArgs.calendarId],
                duplicateSimilarityThreshold: validArgs.duplicateSimilarityThreshold,
            }
        );
        const exactDuplicate = conflicts.duplicates.find(
            (dup: DuplicateInfo) => dup.event.similarity >= CONFLICT_DETECTION_CONFIG.DUPLICATE_THRESHOLDS.BLOCKING
        );
        if (exactDuplicate && validArgs.allowDuplicates !== true) {
            const duplicateDetails = formatConflictWarnings({
                hasConflicts: true,
                duplicates: [exactDuplicate],
                conflicts: []
            });
            const cleanedDetails = duplicateDetails.replace('⚠️ POTENTIAL DUPLICATES DETECTED:', '').trim();
            const similarityPercentage = Math.round(exactDuplicate.event.similarity * 100);
            return this.textResult(`⚠️ DUPLICATE EVENT DETECTED (${similarityPercentage}% similar)!\n\n${cleanedDetails}\n\nThis event appears to be a duplicate. To create anyway, set allowDuplicates to true.`);
        }
        const event = await this.createEvent(oauth2Client, validArgs);
        const text = createEventResponseWithConflicts(event, validArgs.calendarId, conflicts, "created");
        return this.textResult(text);
    }
    private async createEvent(
        client: OAuth2Client,
        args: CreateEventInput
    ): Promise<calendar_v3.Schema$Event> {
        try {
            if (args.eventId) {
                validateEventId(args.eventId);
            }
            const timezone = args.timeZone || await this.getCalendarTimezone(client, args.calendarId);
            const requestBody = buildEventRequestBodyCreate(args, timezone);
            if (args.eventId) {
                requestBody.id = args.eventId;
            }
            const options = getConferenceAndAttachmentOptions(args);
            const calendar = this.getCalendar(client);
            const response = await calendar.events.insert({
                calendarId: args.calendarId,
                requestBody,
                sendUpdates: args.sendUpdates,
                ...options,
            });
            if (!response.data) throw new Error('Failed to create event, no data returned');
            return response.data;
        } catch (error: any) {
            if (error?.code === 409 || error?.response?.status === 409) {
                throw new Error(`Event ID '${args.eventId}' already exists. Please use a different ID.`);
            }
            throw this.handleGoogleApiError(error);
        }
    }
}import { formatEventWithDetails } from '../utils.js';
import { groupBy } from 'lodash-es';
import { ExtendedEvent } from './types.js';
export type { ExtendedEvent };
export interface FormatEventsListOptions {
  groupByCalendar?: boolean;
  header?: string;
}
export function formatEventsList(
  events: ExtendedEvent[],
  options: FormatEventsListOptions = {}
): string {
  const { groupByCalendar = false } = options;
  if (groupByCalendar) {
    return formatGroupedEventsList(events);
  }
  return formatSimpleEventsList(events);
}
function formatSimpleEventsList(events: ExtendedEvent[]): string {
  let text = `Found ${events.length} event(s):\n\n`;
  events.forEach((event, index) => {
    const eventDetails = formatEventWithDetails(event, event.calendarId);
    text += `${index + 1}. ${eventDetails}\n\n`;
  });
  return text.trim();
}
function formatGroupedEventsList(events: ExtendedEvent[]): string {
  const grouped = groupEventsByCalendar(events);
  const calendarCount = Object.keys(grouped).length;
  let text = `Found ${events.length} event(s) across ${calendarCount} calendar(s):\n\n`;
  for (const [calendarId, calendarEvents] of Object.entries(grouped)) {
    text += `Calendar: ${calendarId}\n\n`;
    calendarEvents.forEach((event, index) => {
      const eventDetails = formatEventWithDetails(event, event.calendarId);
      text += `${index + 1}. ${eventDetails}\n\n`;
    });
    text += '\n';
  }
  return text.trim();
}
function groupEventsByCalendar(events: ExtendedEvent[]): Record<string, ExtendedEvent[]> {
  return groupBy(events, (event) => event.calendarId || 'Unknown');
