    'colorId',
    'reminders',
    'recurrence',
    'transparency',
    'visibility',
    'guestsCanInviteOthers',
    'guestsCanModify',
    'guestsCanSeeOtherGuests',
    'anyoneCanAddSelf',
    'conferenceData',
    'extendedProperties',
    'attachments',
    'source'
  ] as const;
