export async function withCleanup<T, C>(
  setup: () => Promise<T>,
  cleanup: (resource: T) => Promise<void>
): Promise<T> {
  const resource = await setup();
  try {
    return resource;
  } finally {
    await cleanup(resource).catch((err) => {
      console.error('Cleanup failed:', err);
    });
  }
