import { calendar_v3 } from 'googleapis';
import { RecurringEventHelpers } from '../../../handlers/core/RecurringEventHelpers.js';
import { makeCalendarMock, makeEvent } from '../helpers/factories.js';
import {
  SYSTEM_FIELDS,
