  });
  describe('cleanEventForDuplication', () => {
    function expectSystemFieldsRemoved(result: calendar_v3.Schema$Event): void {
      SYSTEM_FIELDS.forEach(field => {
        expect(result[field as keyof typeof result]).toBeUndefined();
      });
