      start: { dateTime: '2024-01-15T09:00:00Z' },
      end: { dateTime: '2024-01-15T09:15:00Z' }
    });
    const dup2 = makeEvent({
      id: 'daily-standup',
      summary: 'Daily Team Standup',
      description: 'Quick sync',
      start: { dateTime: '2024-01-15T09:00:00Z' },
      end: { dateTime: '2024-01-15T09:30:00Z' },
      location: 'Zoom'
