          id: 'conflict456',
          title: 'Design Review',
          url: 'https://calendar.google.com/event?eid=conflict456',
          start: '2024-01-15T13:30:00Z',
          end: '2024-01-15T14:30:00Z'
        },
        fullEvent: conflictingEvent,
        overlap: {
          duration: '30 minutes',
