                oauth2Client,
                eventToCheck,
                validArgs.calendarId,
                {
                    checkDuplicates: false,
                    checkConflicts: true,
                    calendarsToCheck: validArgs.calendarsToCheck || [validArgs.calendarId],
                }
            );
        }
