});/**
 * Create Gmail filters and apply them to existing emails.
 * Consolidates create-simple-filters.mjs, create-unread-filters.mjs, and create-remaining-filters.mjs.
 *
 * Usage:
 *   node create-gmail-filters.mjs              # create core filters + apply to existing
 *   node create-gmail-filters.mjs --apply      # apply labels to existing emails only
 *   node create-gmail-filters.mjs --remaining  # create/apply remaining category filters (grouped by label)
 */
import { createGmailClient } from './lib/gmail-client.mjs';
import {
  GMAIL_INBOX,
  LABEL_SENTRY,
  LABEL_MEETUP_EVENTS,
  LABEL_COMMUNITY_EVENTS,
  LABEL_PRODUCT_UPDATES,
  LABEL_CALENDLY_NOTIFICATIONS,
  LABEL_LINKEDIN_UPDATES,
  LABEL_DMARC_REPORTS,
  LABEL_EVENTS,
  LABEL_MEETING_NOTES,
  LABEL_MONITORING,
  LABEL_COMMUNITIES,
  LABEL_SERVICES,
} from './lib/constants.mjs';
import { ensureLabelExists, createGmailFilter } from './lib/gmail-filter-utils.mjs';
import { searchAndModify } from './lib/gmail-batch-utils.mjs';
import { BANNER } from './lib/console-utils.mjs';

const applyOnly = process.argv.includes('--apply');
const remainingMode = process.argv.includes('--remaining');

/**
 * Each entry: label name, Gmail filter criteria query string, and a separate
 * applyQuery used when backfilling existing messages (may differ from filter
 * query to narrow to unread/recent). maxResults is optional.
 */
/** applyQuery defaults to `is:unread <filterQuery>` when omitted. */
const FILTER_CONFIGS = [
  { label: LABEL_SENTRY, filterQuery: 'from:noreply@md.getsentry.com' },
  { label: LABEL_MEETUP_EVENTS, filterQuery: 'from:info@email.meetup.com' },
  { label: LABEL_COMMUNITY_EVENTS, filterQuery: 'from:("ATX - Awkwardly Zen" OR "Austin Cafe Drawing Group" OR "Austin Robotics & AI")' },
  { label: LABEL_PRODUCT_UPDATES, filterQuery: 'from:(noreply@email.openai.com OR no-reply@email.claude.com OR googlecloud@google.com OR "AlphaSignal" OR lukak@storylane.io)' },
  { label: LABEL_CALENDLY_NOTIFICATIONS, filterQuery: 'from:teamcalendly@send.calendly.com' },
  { label: LABEL_LINKEDIN_UPDATES, filterQuery: 'from:updates-noreply@linkedin.com' },
  { label: LABEL_DMARC_REPORTS, filterQuery: 'subject:DMARC', applyQuery: 'subject:DMARC', maxResults: 100 },
  { label: LABEL_EVENTS, filterQuery: 'from:noreply@reminder.eventbrite.com' },
  { label: LABEL_MEETING_NOTES, filterQuery: 'from:meetings-noreply@google.com subject:Notes' },
  { label: LABEL_MONITORING, filterQuery: 'from:alertmanager@signoz.cloud', applyQuery: 'from:alertmanager@signoz.cloud', maxResults: 200 },
];

/** Grouped filter categories for the --remaining mode */
const REMAINING_CATEGORIES = [
  {
    labelName: LABEL_PRODUCT_UPDATES,
    filters: [
      { query: 'from:workspace-noreply@google.com', name: 'Google Workspace' },
      { query: 'from:GoogleCloudStartups@google.com', name: 'Google Cloud Startups' },
      { query: 'from:no-reply@discuss.google.d', name: 'Google Developer Forums' },
      { query: 'from:analytics-noreply@google.com', name: 'Google Analytics' },
      { query: 'from:noreply@notifications.hubspot.com', name: 'HubSpot' },
      { query: 'from:notifications@mail.postman.com', name: 'Postman' },
      { query: 'from:zeno@updates.resend.com', name: 'Resend' },
      { query: 'from:(support@mixpanel.com OR content@mixpanel.com)', name: 'Mixpanel' },
      { query: 'from:noreply@tm.openai.com', name: 'OpenAI' },
      { query: 'from:communications@yodlee.com', name: 'Yodlee' },
      { query: 'from:hello@adapty.io', name: 'Adapty' },
      { query: 'from:no-reply@comms.datahub.com', name: 'DataHub' },
      { query: 'from:arthur@storylane.io', name: 'Storylane' },
    ],
  },
  {
    labelName: LABEL_COMMUNITIES,
    filters: [
      { query: 'from:wtm@technovation.org', name: 'Women Techmakers' },
    ],
  },
  {
    labelName: LABEL_SERVICES,
    filters: [
      { query: 'from:memberservices@founderscard.com', name: 'FoundersCard' },
      { query: 'from:notifications@link.com', name: 'Link' },
      { query: 'from:bot@notifications.heroku.com', name: 'Heroku' },
      { query: 'from:my-saved-home@mail.zillow.com', name: 'Zillow' },
      { query: 'from:upcoming@americanbestech.com', name: 'American Best' },
      { query: 'from:alerts@mail.zapier.com', name: 'Zapier' },
    ],
  },
];

async function runRemainingFilters(gmail) {
  console.log('CREATING FILTERS FOR REMAINING CATEGORIES\n');
  console.log(BANNER + '\n');

  let totalCreated = 0;
  let emailsProcessed = 0;

  for (const categoryConfig of REMAINING_CATEGORIES) {
    console.log(`\n${categoryConfig.labelName.toUpperCase()}\n`);
    const labelId = await ensureLabelExists(gmail, categoryConfig.labelName).catch(err => {
      console.warn(`  Warning: skipping ${categoryConfig.labelName} — ${err.message}`);
      return null;
    });
    if (!labelId) continue;

    for (const filter of categoryConfig.filters) {
      const filterId = await createGmailFilter(gmail, { query: filter.query }, { addLabelIds: [labelId], removeLabelIds: [GMAIL_INBOX] });
      console.log(filterId ? `  ${filter.name}` : `  ${filter.name} (already exists)`);
      if (filterId) totalCreated++;
    }

    const queries = categoryConfig.filters.map(f => `(${f.query})`).join(' OR ');
    const count = await searchAndModify(gmail, queries, { addLabelIds: [labelId], removeLabelIds: [GMAIL_INBOX] }, 100);
    if (count > 0) {
      console.log(`${categoryConfig.labelName}: ${count} emails labeled and archived`);
      emailsProcessed += count;
    }
  }

  console.log('\n' + BANNER);
  console.log(`Filters created: ${totalCreated} | Emails processed: ${emailsProcessed}\n`);
  console.log(BANNER + '\n');
}

async function run() {
  const gmail = createGmailClient();

  if (remainingMode) {
    await runRemainingFilters(gmail);
    return;
  }

  console.log(applyOnly ? 'APPLYING LABELS TO EXISTING EMAILS\n' : 'CREATING AUTO-ARCHIVE FILTERS\n');
  console.log(BANNER + '\n');

  let created = 0;
  let errors = 0;
  let emailsProcessed = 0;

  for (const config of FILTER_CONFIGS) {
    let labelId;
    try {
      labelId = await ensureLabelExists(gmail, config.label);
    } catch (error) {
      console.log(`  Error creating label ${config.label}: ${error.message}`);
      errors++;
      continue;
    }

    if (!applyOnly) {
      const filterId = await createGmailFilter(gmail, { query: config.filterQuery }, { addLabelIds: [labelId], removeLabelIds: [GMAIL_INBOX] });
      console.log(filterId ? `  Filter created: ${config.label}` : `  Filter already exists: ${config.label}`);
      if (filterId) created++;
    }

    const applyQuery = config.applyQuery ?? `is:unread ${config.filterQuery}`;
    const count = await searchAndModify(gmail, applyQuery, { addLabelIds: [labelId], removeLabelIds: [GMAIL_INBOX] }, config.maxResults);
    if (count > 0) {
      console.log(`  ${config.label}: labeled and archived ${count} existing emails`);
      emailsProcessed += count;
    }
  }

  console.log('\n' + BANNER);
  if (!applyOnly) {
    console.log(`Filters created: ${created} | Errors: ${errors} | Emails processed: ${emailsProcessed}\n`);
  } else {
    console.log(`Emails processed: ${emailsProcessed}\n`);
  }
  console.log(BANNER + '\n');
}

run().catch(error => {
  console.error('Error:', error.message);
  process.exit(1);
});import { createGmailClient } from './lib/gmail-client.mjs';
import { USER_ID, GMAIL_INBOX, LABEL_EVENTS, LABEL_KEEP_IMPORTANT } from './lib/constants.mjs';
import { classifyEmail } from './lib/date-based-filter.mjs';
import { getHeader } from './lib/email-utils.mjs';
import { batchModifyMessages } from './lib/gmail-batch-utils.mjs';
import { buildLabelCache } from './lib/gmail-label-utils.mjs';
import { BANNER } from './lib/console-utils.mjs';
import { decodeMessageBody } from './lib/gmail-message-utils.mjs';

const EVENT_KEYWORDS = '(event OR meeting OR conference OR workshop OR seminar OR webinar OR presentation OR summit OR expo OR networking OR panel OR forum OR gathering OR ceremony OR celebration)';
const EVENT_SENDERS = '(meetup OR eventbrite OR "international house" OR calendly OR calendar)';

async function filterEventsByDate() {
  const gmail = createGmailClient();

  console.log('FILTERING EVENTS BY DATE (WITH DATE-BASED ARCHIVE)\n');
  console.log(BANNER + '\n');

  const labelCache = await buildLabelCache(gmail);
  const eventsLabelId = labelCache.get(LABEL_EVENTS);
  const keepImportantLabelId = labelCache.get(LABEL_KEEP_IMPORTANT);

  if (!eventsLabelId) {
    console.log('Events label not found\n');
    process.exit(1);
  }

  const searchQuery = `is:unread (subject:${EVENT_KEYWORDS} OR from:${EVENT_SENDERS}) ${keepImportantLabelId ? `-label:"${LABEL_KEEP_IMPORTANT}"` : ''}`;
  const searchResponse = await gmail.users.messages.list({ userId: USER_ID, q: searchQuery, maxResults: 100 });
  const messageIds = searchResponse.data.messages || [];
  console.log(`Found ${messageIds.length} event-like emails\n`);

  if (messageIds.length === 0) {
    console.log('No event emails to process\n');
    return;
  }

  const fullMsgs = await Promise.all(
    messageIds.map(msg =>
      gmail.users.messages.get({ userId: USER_ID, id: msg.id, format: 'full' })
        .catch(error => { console.log(`Error processing email: ${error.message}`); return null; })
    )
  );

  const futureIds = [];
  const pastIds = [];

  for (const fullMsg of fullMsgs.filter(Boolean)) {
    const headers = fullMsg.data.payload?.headers || [];
    const subject = getHeader(headers, 'Subject');
    const body = decodeMessageBody(fullMsg.data.payload);
    const classification = classifyEmail(subject, body);
    if (classification.status === 'future') futureIds.push(fullMsg.data.id);
    else if (classification.status === 'past') pastIds.push(fullMsg.data.id);
  }

  const unknownCount = messageIds.length - futureIds.length - pastIds.length;
  console.log(`Future events: ${futureIds.length} | Past events: ${pastIds.length} | Unknown: ${unknownCount}\n`);

  if (futureIds.length > 0) {
    await batchModifyMessages(gmail, futureIds, { addLabelIds: [eventsLabelId] });
  }
  if (pastIds.length > 0) {
    await batchModifyMessages(gmail, pastIds, { addLabelIds: [eventsLabelId], removeLabelIds: [GMAIL_INBOX] });
  }

  console.log(BANNER);
  console.log('COMPLETE\n');
  console.log(`Future events labeled: ${futureIds.length} | Past events archived: ${pastIds.length} | Unknown: ${unknownCount}\n`);
  console.log(BANNER + '\n');
}

filterEventsByDate().catch(error => {
  console.error('Error:', error.message);
  process.exit(1);
